import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define custom CUDA kernel for fused LayerNorm
layernorm_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>
#include <assert.h>

// Minimum epsilon for float32 to prevent underflow in rsqrtf
#define MIN_EPSILON 1e-8f

// Two-pass variance calculation for better numerical stability
__device__ __forceinline__ void compute_stable_variance(
    const float* values, 
    int n, 
    float* mean_out, 
    float* var_out,
    int start_idx,
    int stride
) {
    // First pass: compute mean
    float sum = 0.0f;
    for (int i = start_idx; i < n; i += stride) {
        sum += values[i];
    }

    float mean = sum / n;

    // Second pass: compute variance with compensated summation
    float var = 0.0f;
    float compensation = 0.0f;  // Kahan summation compensation

    for (int i = start_idx; i < n; i += stride) {
        float diff = values[i] - mean;
        float term = diff * diff - compensation;
        float temp = var + term;
        compensation = (temp - var) - term;
        var = temp;
    }

    *mean_out = mean;
    *var_out = var / n;
}

template<typename T>
__device__ __forceinline__ float convert_to_float(T val) {
    return static_cast<float>(val);
}

template<>
__device__ __forceinline__ float convert_to_float<half>(half val) {
    return __half2float(val);
}

template<typename T>
__device__ __forceinline__ T convert_from_float(float val) {
    return static_cast<T>(val);
}

template<>
__device__ __forceinline__ half convert_from_float<half>(float val) {
    return __float2half_rn(val);
}

template<typename T>
__global__ void layernorm_fused_kernel(
    const T* __restrict__ input,
    T* __restrict__ output,
    const T* __restrict__ gamma,
    const T* __restrict__ beta,
    const float eps,
    const int num_elements,
    const int feature_size
) {
    extern __shared__ float shared_mem[];

    int batch_idx = blockIdx.x;
    int tid = threadIdx.x;

    const T* batch_input = input + batch_idx * feature_size;
    T* batch_output = output + batch_idx * feature_size;

    // Apply epsilon lower bound for numerical stability
    float safe_eps = fmaxf(eps, MIN_EPSILON);

    // Phase 1: Load data into shared memory with float conversion
    float* values = shared_mem;  // First feature_size elements

    for (int i = tid; i < feature_size; i += blockDim.x) {
        values[i] = convert_to_float(batch_input[i]);
    }
    __syncthreads();

    // Phase 2: Compute mean using parallel reduction
    float sum = 0.0f;
    for (int i = tid; i < feature_size; i += blockDim.x) {
        sum += values[i];
    }

    float* reduction_mem = shared_mem + feature_size;
    reduction_mem[tid] = sum;
    __syncthreads();

    // Parallel reduction for mean
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            reduction_mem[tid] += reduction_mem[tid + stride];
        }
        __syncthreads();
    }

    float mean = reduction_mem[0] / feature_size;
    __syncthreads();

    // Phase 3: Compute variance using compensated parallel reduction
    float var_sum = 0.0f;
    float compensation = 0.0f;  // Kahan compensation for numerical stability

    for (int i = tid; i < feature_size; i += blockDim.x) {
        float diff = values[i] - mean;
        float term = diff * diff - compensation;
        float temp = var_sum + term;
        compensation = (temp - var_sum) - term;
        var_sum = temp;
    }

    reduction_mem[tid] = var_sum;
    __syncthreads();

    // Parallel reduction for variance
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            reduction_mem[tid] += reduction_mem[tid + stride];
        }
        __syncthreads();
    }

    float variance = reduction_mem[0] / feature_size;

    // Stable inverse std calculation
    float inv_std;
    if (variance <= 0.0f) {
        // Handle zero variance case
        inv_std = 1.0f / sqrtf(safe_eps);
    } else {
        // Use sqrtf instead of rsqrtf for better precision control
        inv_std = 1.0f / sqrtf(variance + safe_eps);
    }

    // Phase 4: Apply normalization with gamma and beta
    for (int i = tid; i < feature_size; i += blockDim.x) {
        float normalized = (values[i] - mean) * inv_std;
        float gamma_val = convert_to_float(gamma[i % num_elements]);
        float beta_val = convert_to_float(beta[i % num_elements]);
        normalized = normalized * gamma_val + beta_val;

        batch_output[i] = convert_from_float<T>(normalized);
    }
}

torch::Tensor layernorm_fused_cuda(
    torch::Tensor input,
    torch::Tensor gamma,
    torch::Tensor beta,
    float eps
) {
    // Validate epsilon parameter
    if (eps < 0.0f) {
        throw std::runtime_error("Epsilon must be non-negative");
    }

    auto sizes = input.sizes();
    int batch_size = 1;
    for (int i = 0; i < sizes.size() - gamma.sizes().size(); i++) {
        batch_size *= sizes[i];
    }

    int feature_size = 1;
    for (int i = sizes.size() - gamma.sizes().size(); i < sizes.size(); i++) {
        feature_size *= sizes[i];
    }

    int num_elements = gamma.numel();

    auto output = torch::empty_like(input);

    // Configure grid and block
    dim3 grid(batch_size);
    int block_size = 256;
    while (block_size > feature_size && block_size > 32) {
        block_size >>= 1;
    }

    // Ensure block_size is power of 2 for reduction
    block_size = 1 << static_cast<int>(log2f(static_cast<float>(block_size)));

    // Calculate shared memory size: values + reduction buffer
    size_t shared_mem_size = (feature_size + block_size) * sizeof(float);

    // Launch kernel based on data type
    AT_DISPATCH_FLOATING_TYPES_AND_HALF(
        input.scalar_type(),
        "layernorm_fused_kernel",
        ([&] {
            layernorm_fused_kernel<scalar_t><<<grid, block_size, shared_mem_size>>>(
                input.data_ptr<scalar_t>(),
                output.data_ptr<scalar_t>(),
                gamma.data_ptr<scalar_t>(),
                beta.data_ptr<scalar_t>(),
                eps,
                num_elements,
                feature_size
            );
        })
    );

    return output;
}
